script:
frappe.ui.form.on('User', {
    refresh: function(frm) {
        if (frappe.user.has_role('System Manager')) {
            if (!frm.doc.__islocal) {
                frm.add_custom_button(__('Allow only for this Organization'), function() {
                    frm.set_value('restrict_to_company', 1);
                    frm.refresh_field('restrict_to_company');
                    frm.refresh_field('allowed_company');
                }, __('Actions'));
            }
        } else {
            frm.set_df_property('restrict_to_company', 'hidden', 1);
            frm.set_df_property('allowed_company', 'hidden', 1);
        }
    }
});
